import { useMemo, useState, useEffect, useRef } from "react";
import { Link, useSearchParams } from "react-router-dom";
import { Star, X, Bell, TrendingUp, TrendingDown, Minus, ArrowUpRight, AlertTriangle, ArrowDownAZ, CalendarClock, DollarSign, Search, Heart, ChevronDown } from "lucide-react";
import { useMarket } from "@/lib/MarketContext";
import { useWatchlists } from "@/lib/useFavorites";
import { useAlerts } from "@/lib/useNotesAlerts";
import { fmt, fmtTime } from "@/lib/parseItem";
import { openItem } from "@/components/landing/DetailDrawer";
import ItemName from "@/components/landing/ItemName";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { Reveal } from "@/components/landing/motion";
import BackToTop from "@/components/landing/BackToTop";
import {
  AlertDialog,
  AlertDialogTrigger,
  AlertDialogContent,
  AlertDialogHeader,
  AlertDialogFooter,
  AlertDialogTitle,
  AlertDialogDescription,
  AlertDialogAction,
  AlertDialogCancel,
} from "@/components/ui/alert-dialog";

const SORTS = [
  { id: "recent", label: "Most recent", Icon: CalendarClock },
  { id: "name",   label: "Name (A–Z)",  Icon: ArrowDownAZ },
  { id: "priceDesc", label: "Price (high → low)", Icon: DollarSign },
  { id: "priceAsc",  label: "Price (low → high)",  Icon: DollarSign },
];

export default function FavoritesPage() {
  const { market, loading } = useMarket();
  const [searchParams, setSearchParams] = useSearchParams();
  const watchlists = useWatchlists();
  const alerts = useAlerts();
  const [alertsOpen, setAlertsOpen] = useState(false);
  const alertEntries = useMemo(() => {
    const entries = Object.entries(alerts.all);
    return entries.map(([key, alert]) => ({
      key,
      alert,
      item: market?.rowsByKey.get(key) || null,
    }));
  }, [alerts.all, market?.rowsByKey]);
  const [sortId, setSortId] = useState("recent");
  const [q, setQ] = useState("");
  const searchRef = useRef(null);
  const currentListName = watchlists.lists.find(l => l.id === watchlists.currentId)?.name || "Favorites";

  // Pressing "/" focuses the local search bar instead of opening the
  // global command palette. Only when the user isn't already typing.
  useEffect(() => {
    const handler = (e) => {
      if (e.key !== "/") return;
      const tag = (document.activeElement?.tagName || "").toLowerCase();
      if (tag === "input" || tag === "textarea" || tag === "select") return;
      e.preventDefault();
      searchRef.current?.focus();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);

  const items = useMemo(() => {
    if (!market) return [];
    const rows = watchlists.items
      .map((k) => market.rowsByKey.get(k))
      .filter(Boolean);
    const query = q.trim().toLowerCase();
    // Match name, raw key, category, and modifier tags (e.g. typing
    // "farming" finds a starred Knowledge Cap [Farming]). Mirrors the
    // ListingsPage filter.
    const filtered = query
      ? rows.filter((r) =>
          r.name.toLowerCase().includes(query) ||
          r.key.toLowerCase().includes(query) ||
          r.category.toLowerCase().includes(query) ||
          (r.modifiers || []).some((m) => m.toLowerCase().includes(query)),
        )
      : rows;
    const sorted = [...filtered];
    switch (sortId) {
      case "name":      sorted.sort((a, b) => a.name.localeCompare(b.name)); break;
      case "priceDesc": sorted.sort((a, b) => b.median - a.median); break;
      case "priceAsc":  sorted.sort((a, b) => a.median - b.median); break;
      case "recent":
      default: break; // watchlists.items is already most-recent-first
    }
    return sorted;
  }, [market, watchlists.items, sortId, q]);

  const totalValue = useMemo(() => items.reduce((s, r) => s + (r.median || 0), 0), [items]);

  const Trend = ({ trend }) => {
    const Icon = trend === "up" ? TrendingUp : trend === "down" ? TrendingDown : Minus;
    const color = trend === "up" ? "text-red-400" : trend === "down" ? "text-emerald-400" : "text-zinc-500";
    return <Icon className={`w-4 h-4 ${color}`} />;
  };

  return (
    <div data-testid="favorites-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-amber-400 mb-4 inline-flex items-center gap-2">
              <Heart className="w-3 h-3" /> / Favorites
            </div>
            <h1 className="font-heading text-5xl sm:text-6xl lg:text-7xl tracking-tighter font-black leading-[0.95]">
              <span className="text-amber-400 tabular">{watchlists.count}</span> starred item{watchlists.count === 1 ? "" : "s"}.
              <br />
              Your watchlist.
            </h1>
            <p className="mt-6 text-zinc-400 max-w-2xl text-lg">
              Every item you've starred from the listings, with live medians. Click a row to open the detail panel, or use <span className="kbd">/</span> to filter.
            </p>
          </Reveal>

          {/* Watchlist selector */}
          {watchlists.lists.length > 1 && (
            <Reveal delay={0.04}>
              <div className="mt-8 flex flex-wrap items-center gap-2">
                {watchlists.lists.map((list) => {
                  const active = list.id === watchlists.currentId;
                  return (
                    <button
                      key={list.id}
                      onClick={() => watchlists.switchList(list.id)}
                      className={`inline-flex items-center gap-2 px-4 py-2 rounded-md font-mono text-[11px] uppercase tracking-wider transition-colors ${
                        active
                          ? "bg-amber-500/15 text-amber-300 border border-amber-500/30"
                          : "bg-white/[0.02] text-zinc-400 hover:text-white border border-white/10"
                      }`}
                    >
                      {active && <Star className="w-3 h-3 fill-amber-400" />}
                      {list.name}
                    </button>
                  );
                })}
              </div>
            </Reveal>
          )}

          {/* Toolbar */}
          <div className="mt-10 flex flex-wrap items-center gap-3">
            <div className="relative flex-1 min-w-[140px] sm:min-w-[200px]">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
              <input
                ref={searchRef}
                data-testid="fav-search"
                value={q}
                onChange={(e) => setQ(e.target.value)}
                placeholder="Filter favorites…"
                aria-label="Filter favorites"
                className="w-full bg-white/[0.02] border border-white/10 focus:border-emerald-500/40 rounded-md pl-10 pr-10 py-2.5 text-sm text-white placeholder-zinc-500 outline-none transition-colors"
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 kbd">/</span>
            </div>
            <div className="flex items-center gap-1.5 bg-white/[0.02] border border-white/10 rounded-md p-1">
              {SORTS.map((s) => {
                const Icon = s.Icon;
                const active = sortId === s.id;
                return (
                  <button
                    key={s.id}
                    data-testid={`fav-sort-${s.id}`}
                    onClick={() => setSortId(s.id)}
                    className={`inline-flex items-center gap-1.5 px-2.5 py-1.5 rounded-sm font-mono text-[10px] uppercase tracking-wider transition-colors ${active ? "bg-emerald-500/15 text-emerald-300" : "text-zinc-400 hover:text-white"}`}
                  >
                    <Icon className="w-3 h-3" />
                    {s.label}
                  </button>
                );
              })}
            </div>
            {watchlists.count > 0 && (
              <AlertDialog>
                <AlertDialogTrigger asChild>
                  <button
                    data-testid="fav-clear"
                    className="inline-flex items-center gap-1.5 border border-white/10 hover:border-red-500/40 hover:text-red-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
                  >
                    <X className="w-3 h-3" /> Clear all
                  </button>
                </AlertDialogTrigger>
                <AlertDialogContent className="bg-bg-base border-white/10 text-white">
                  <AlertDialogHeader>
                    <AlertDialogTitle>Clear all {currentListName} items?</AlertDialogTitle>
                    <AlertDialogDescription className="text-zinc-400">
                      This will remove all {watchlists.count} items from &ldquo;{currentListName}&rdquo;.
                    </AlertDialogDescription>
                  </AlertDialogHeader>
                  <AlertDialogFooter>
                    <AlertDialogCancel className="border-white/10 text-zinc-300 hover:bg-white/5">Cancel</AlertDialogCancel>
                    <AlertDialogAction
                      onClick={() => watchlists.clear()}
                      className="bg-red-500 hover:bg-red-400 text-black font-bold"
                    >
                      Clear all
                    </AlertDialogAction>
                  </AlertDialogFooter>
                </AlertDialogContent>
              </AlertDialog>
            )}
          </div>

          {/* Empty state */}
          {watchlists.count === 0 && !loading.market && (
            <Reveal>
              <div data-testid="fav-empty" className="mt-16 text-center max-w-md mx-auto">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-amber-500/10 border border-amber-500/30 mb-6">
                  <Star className="w-7 h-7 text-amber-400" />
                </div>
                <h2 className="font-heading text-2xl font-black mb-3">No favorites yet</h2>
                <p className="text-zinc-400 text-sm leading-relaxed mb-6">
                  Star items from the listings to track them here. Your watchlist lives in your browser — no account needed.
                </p>
                <Link
                  to="/listings"
                  data-testid="fav-empty-browse"
                  className="inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-5 py-3 rounded-sm transition-colors"
                >
                  Browse listings <ArrowUpRight className="w-4 h-4" />
                </Link>
              </div>
            </Reveal>
          )}

          {/* Active alerts */}
          {alerts.count > 0 && (
            <Reveal delay={0.08}>
              <div className="mt-8 border border-amber-500/20 rounded-2xl overflow-hidden bg-amber-500/[0.02]">
                <button
                  onClick={() => setAlertsOpen(!alertsOpen)}
                  className="w-full flex items-center justify-between px-5 py-4 text-left"
                  aria-expanded={alertsOpen}
                >
                  <div className="inline-flex items-center gap-2">
                    <Bell className="w-4 h-4 text-amber-400" />
                    <span className="font-heading font-bold text-sm text-white">{alerts.count} active alert{alerts.count === 1 ? "" : "s"}</span>
                  </div>
                  <ChevronDown className={`w-4 h-4 text-zinc-500 transition-transform ${alertsOpen ? "rotate-180" : ""}`} />
                </button>
                {alertsOpen && (
                  <div className="border-t border-amber-500/10 divide-y divide-amber-500/10">
                    {alertEntries.map(({ key, alert, item }) => (
                      <div key={key} className="flex items-center justify-between px-5 py-3">
                        <div className="min-w-0 flex-1">
                          <div className="font-heading font-bold text-sm text-white truncate">
                            {item?.name || key}
                          </div>
                          <div className="font-mono text-[10px] uppercase tracking-wider text-zinc-500 mt-0.5">
                            {alert.kind === "below" ? "Drops below" : "Rises above"}{" "}
                            <span className="text-amber-400">{fmt(alert.value)}</span>
                          </div>
                        </div>
                        <button
                          onClick={() => alerts.set(key, null)}
                          data-testid={`alert-remove-${key}`}
                          className="shrink-0 p-1.5 text-zinc-500 hover:text-red-400 transition-colors"
                          aria-label="Remove alert"
                        >
                          <X className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </Reveal>
          )}

          {/* Stat strip */}
          {items.length > 0 && (
            <Reveal delay={0.1}>
              <div className="mt-6 grid grid-cols-2 md:grid-cols-4 gap-px bg-white/10 border border-white/10 rounded-lg overflow-hidden">
                {[
                  { l: "Items",     v: items.length },
                  { l: "Showing",   v: items.length },
                  { l: "Est. value", v: totalValue > 0 ? fmt(totalValue) : "—" },
                  { l: "Last sync", v: market?.stats.lastUpdated ?? "—" },
                ].map((s) => (
                  <div key={s.l} className="bg-bg-base p-4">
                    <div className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">{s.l}</div>
                    <div className="mt-1 font-heading text-2xl font-black tabular text-white">{s.v}</div>
                  </div>
                ))}
              </div>
            </Reveal>
          )}

          {/* Table */}
          {items.length > 0 && (
            <Reveal delay={0.15} className="mt-8">
              <div className="border border-white/10 rounded-2xl overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="bg-white/[0.02] border-b border-white/10 text-left">
                      <th className="px-4 py-3 w-12"></th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">Item</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden sm:table-cell">Category</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 text-right">Median</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden md:table-cell">Trend</th>
                      <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden lg:table-cell">Last seen</th>
                      <th className="px-4 py-3 w-12"></th>
                    </tr>
                  </thead>
                  <tbody>
                    {items.map((r) => (
                      <tr
                        key={r.key}
                        data-testid={`fav-row-${r.key}`}
                        onClick={() => openItem(searchParams, setSearchParams, r.key)}
                        onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); openItem(searchParams, setSearchParams, r.key); } }}
                        tabIndex={0}
                        role="link"
                        className="border-b border-white/5 last:border-0 hover:bg-white/[0.03] transition-colors cursor-pointer group"
                      >
                        <td className="px-4 py-4">
                          <button
                            onClick={(e) => { e.stopPropagation(); watchlists.toggle(r.key); }}
                            data-testid={`fav-remove-${r.key}`}
                            aria-label="Remove from favorites"
                            className="p-1 text-amber-400 hover:text-amber-300 transition-colors"
                          >
                            <Star className="w-4 h-4 fill-amber-400" />
                          </button>
                        </td>
                        <td className="px-4 py-4">
                          <div className="font-heading font-bold text-white group-hover:text-emerald-400 transition-colors">
                            <ItemName name={r.name} tier={r.tier} modifiers={r.modifiers} />
                          </div>
                        </td>
                        <td className="px-4 py-4 hidden sm:table-cell">
                          <span className="font-mono text-[10px] uppercase tracking-wider text-zinc-500">{r.category}</span>
                        </td>
                        <td className="px-4 py-4 text-right">
                          <span className="font-mono tabular text-white font-bold">{r.median > 0 ? fmt(r.median) : "—"}</span>
                        </td>
                        <td className="px-4 py-4 hidden md:table-cell">
                          <div className="inline-flex items-center gap-1.5">
                            <Trend trend={r.trend} />
                            <span className="font-mono text-[10px] uppercase tracking-wider text-zinc-500">{r.trend}</span>
                          </div>
                        </td>
                        <td className="px-4 py-4 hidden lg:table-cell">
                          <span className="font-mono text-[10px] text-zinc-500">{fmtTime(r.lastSeenMs)}</span>
                        </td>
                        <td className="px-4 py-4 text-zinc-600 group-hover:text-emerald-400 transition-colors">
                          <ArrowUpRight className="w-4 h-4" />
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </Reveal>
          )}

          {q && items.length === 0 && watchlists.count > 0 && (
            <div data-testid="fav-no-matches" className="mt-12 text-center text-zinc-500 text-sm font-mono uppercase tracking-wider">
              <AlertTriangle className="w-4 h-4 inline-block mr-2" />
              No favorites match "{q}"
            </div>
          )}
        </div>
      </main>
      <Footer />
      <BackToTop />
    </div>
  );
}
